func TestTruncateBody(t *testing.T) {
	t.Parallel()

	const maxBytes = 4096

	cases := []struct {
		name        string
		input       []byte
		wantLen     int
		wantHasTail bool
	}{
		{"empty", nil, 0, false},
		{"under cap", []byte("hello"), 5, false},
		{"at cap", bytes.Repeat([]byte("a"), maxBytes), maxBytes, false},
		{"one over cap", bytes.Repeat([]byte("a"), maxBytes+1), maxBytes + 3, true},
		{"huge body", bytes.Repeat([]byte("a"), maxBytes*8), maxBytes + 3, true},
	}

	for _, tc := range cases {
		tc := tc
		t.Run(tc.name, func(t *testing.T) {
			t.Parallel()
			got := truncateBody(tc.input)
			if len(got) != tc.wantLen {
				t.Fatalf("len = %d, want %d", len(got), tc.wantLen)
			}
			if tc.wantHasTail && !strings.HasSuffix(got, "...") {
				t.Fatalf("want trailing %q", "...")
			}
			if !tc.wantHasTail && strings.HasSuffix(got, "...") {
				t.Fatalf("unexpected trailing %q in %q", "...", got)
			}
		})
	}
}

func TestTruncateBody_UTF8RuneAtBoundary(t *testing.T) {
	t.Parallel()

	// '€' is 3 bytes (0xE2 0x82 0xAC). Place it so the slice at byte 4096 cuts
	// mid-rune; strings.ToValidUTF8 should drop the partial rune cleanly rather
	// than emit U+FFFD or invalid UTF-8.
	prefix := strings.Repeat("a", 4094)
	body := []byte(prefix + "€" + strings.Repeat("b", 100))
	got := truncateBody(body)

	if !utf8.ValidString(got) {
		t.Fatalf("output is not valid UTF-8")
	}
	if strings.ContainsRune(got, utf8.RuneError) {
		t.Fatalf("output contains replacement rune U+FFFD")
	}
	if !strings.HasSuffix(got, "...") {
		t.Fatalf("want trailing %q", "...")
	}
	// Partial rune must be dropped, not replaced: 4094 valid bytes + "...".
	if want := 4094 + 3; len(got) != want {
		t.Fatalf("len = %d, want %d (partial rune should be dropped, not replaced)", len(got), want)
	}
}

func TestCheckRedirectStripsAPIKeyOnCrossHostRedirect(t *testing.T) {
	t.Parallel()

	c := New(&config.Config{
		BaseURL:   "https://api.kit.com",
		KitApiKey: "secret-key",
	}, time.Second, 0)

	previous := &http.Request{URL: mustURL(t, "https://api.kit.com/v4/account")}
	next := &http.Request{
		URL:    mustURL(t, "https://example.com/redirected"),
		Header: http.Header{"X-Kit-Api-Key": []string{"secret-key"}},
	}

	if err := c.HTTPClient.CheckRedirect(next, []*http.Request{previous}); err != nil {
		t.Fatalf("CheckRedirect returned error: %v", err)
	}
	if got := next.Header.Get("X-Kit-Api-Key"); got != "" {
		t.Fatalf("cross-host redirect retained API key %q", got)
	}
}

func TestCheckRedirectReaddsAPIKeyOnSameHostRedirect(t *testing.T) {
	t.Parallel()

	c := New(&config.Config{
		BaseURL:   "https://api.kit.com",
		KitApiKey: "secret-key",
	}, time.Second, 0)

	previous := &http.Request{URL: mustURL(t, "https://api.kit.com/v4/account")}
	next := &http.Request{
		URL:    mustURL(t, "https://api.kit.com/v4/creator_profile"),
		Header: http.Header{},
	}

	if err := c.HTTPClient.CheckRedirect(next, []*http.Request{previous}); err != nil {
		t.Fatalf("CheckRedirect returned error: %v", err)
	}
	if got := next.Header.Get("X-Kit-Api-Key"); got != "secret-key" {
		t.Fatalf("same-host redirect API key = %q, want %q", got, "secret-key")
	}
}

func mustURL(t *testing.T, raw string) *url.URL {
	t.Helper()

	u, err := url.Parse(raw)
	if err != nil {
		t.Fatalf("parse URL %q: %v", raw, err)
	}
	return u
}
